class Solution {
    public int minSwapsCouples(int[] row) {
        int n = row.length;
        int swaps = 0;
        for (int i = 0; i < n; i += 2) {
            int j = i + 1;
            while (j < n && row[j] % 2 != 0) {
                swap(row, i, j);
                swaps++;
                j++;
            }
        }
        return swaps;
    }

    public void swap(int[] array, int i, int j) {
        int temp = array[i];
        array[i] = array[j];
        array[j] = temp;
    }
}
```

